index c06d5c759634..e8137801e0b5 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
@@ -1135,6 +1135,71 @@ static Value *foldUnsignedUnderflowCheck(ICmpInst *ZeroICmp,
   return nullptr;
 }

+/// Fold (icmp ne X, -1) & (icmp ule (add X, 1), Y) -> icmp ult X, Y.
+/// Fold (icmp eq X, -1) | (icmp ugt (add X, 1), Y) -> icmp uge X, Y.
+/// And commutative variants.
+static Value *foldAddNoOverflowAndICmp(ICmpInst *Cmp0, ICmpInst *Cmp1,
+                                       bool IsAnd,
+                                       InstCombiner::BuilderTy &Builder) {
+  ICmpInst::Predicate Pred0 = Cmp0->getPredicate();
+  ICmpInst::Predicate Pred1 = Cmp1->getPredicate();
+  Value *X, *Y;
+  const APInt *One;
+  // Match one icmp as X != -1 (or X == -1)
+  ICmpInst *MaybeMaxCmp = nullptr;
+  ICmpInst *MaybeAddCmp = nullptr;
+  bool IsNe;
+  auto MatchMaxCmp = [&](ICmpInst *Cmp, ICmpInst *Other) -> bool {
+    if (Cmp->getPredicate() != ICmpInst::ICMP_NE &&
+        Cmp->getPredicate() != ICmpInst::ICMP_EQ)
+      return false;
+    Value *LHS = Cmp->getOperand(0);
+    Value *RHS = Cmp->getOperand(1);
+    if (match(RHS, m_AllOnes())) {
+      X = LHS;
+    } else if (match(LHS, m_AllOnes())) {
+      X = RHS;
+    } else
+      return false;
+    MaybeMaxCmp = Cmp;
+    MaybeAddCmp = Other;
+    IsNe = Cmp->getPredicate() == ICmpInst::ICMP_NE;
+    return true;
+  };
+  if (!MatchMaxCmp(Cmp0, Cmp1) && !MatchMaxCmp(Cmp1, Cmp0))
+    return nullptr;
+  // Now match the other icmp as (add X, 1) <= Y (or >)
+  Value *Add;
+  if (!match(MaybeAddCmp->getOperand(0), m_Add(m_Specific(X), m_APInt(One))) ||
+      *One != 1) {
+    // Could also be swapped: Y >= (add X, 1)
+    if (!match(MaybeAddCmp->getOperand(1), m_Add(m_Specific(X), m_APInt(One))) ||
+        *One != 1)
+      return nullptr;
+    Y = MaybeAddCmp->getOperand(0);
+  } else {
+    Y = MaybeAddCmp->getOperand(1);
+  }
+  ICmpInst::Predicate AddPred = MaybeAddCmp->getPredicate();
+  // Determine the combined predicate.
+  // (X != -1) && (X+1 <= Y) -> X < Y
+  // (X == -1) || (X+1 > Y) -> X >= Y
+  // For AND, we need IsNe true and AddPred is ULE (or ULT? Actually ule)
+  // For OR, we need IsNe false and AddPred is UGT (or UGE?)
+  if (IsAnd == IsNe) {
+    // Expect IsAnd true, IsNe true -> both conditions must be true.
+    // AddPred must be ICMP_ULE or ICMP_ULT? Let's allow both.
+    if (AddPred != ICmpInst::ICMP_ULE && AddPred != ICmpInst::ICMP_ULT)
+      return nullptr;
+    // Transform to ICMP_ULT.
+    return Builder.CreateICmpULT(X, Y);
+  } else {
+    // IsAnd false, IsNe false -> OR with eq and ugt.
+    if (AddPred != ICmpInst::ICMP_UGT && AddPred != ICmpInst::ICMP_UGE)
+      return nullptr;
+    return Builder.CreateICmpUGE(X, Y);
+  }
+}
 struct IntPart {
   Value *From;
   unsigned StartBit;
@@ -3099,6 +3164,7 @@ Value *InstCombinerImpl::foldAndOrOfICmps(ICmpInst *LHS, ICmpInst *RHS,
   if (Value *V = foldPowerOf2AndShiftedMask(LHS, RHS, IsAnd, Builder))
     return V;

+  // TODO: Verify whether this is safe for logical and/or.
   // TODO: Verify whether this is safe for logical and/or.
   if (!IsLogical) {
     if (Value *X = foldUnsignedUnderflowCheck(LHS, RHS, IsAnd, Q, Builder))
@@ -3106,6 +3172,10 @@ Value *InstCombinerImpl::foldAndOrOfICmps(ICmpInst *LHS, ICmpInst *RHS,
     if (Value *X = foldUnsignedUnderflowCheck(RHS, LHS, IsAnd, Q, Builder))
       return X;
   }
+  if (Value *X = foldAddNoOverflowAndICmp(LHS, RHS, IsAnd, Builder))
+    return X;
+  if (Value *X = foldAddNoOverflowAndICmp(RHS, LHS, IsAnd, Builder))
+    return X;

   if (Value *X = foldEqOfParts(LHS, RHS, IsAnd))
     return X;

